<script setup lang="ts">
import { nextTick,onMounted,ref,watch } from 'vue'; import { useChatStore } from '@/stores/chat'; import { useHealthCasesStore } from '@/stores/healthCases'; import ChatSidebar from '@/components/chat/ChatSidebar.vue'; import ChatMessages from '@/components/chat/ChatMessages.vue'; import ChatInput from '@/components/chat/ChatInput.vue'; import HealthCasePanel from '@/components/health/HealthCasePanel.vue'; import GuidancePanel from '@/components/health/GuidancePanel.vue'
const chat=useChatStore(); const cases=useHealthCasesStore(); const value=ref(''); const messagesRef=ref<InstanceType<typeof ChatMessages>|null>(null); const tab=ref<'case'|'guide'>('case')
onMounted(async()=>{await cases.loadCases(); await chat.obtenerOCrearConversacion()}); watch(()=>chat.mensajes.length,async()=>{await nextTick();messagesRef.value?.scrollToBottom()})
async function send(){const current=value.value;value.value='';await chat.enviarMensaje(current)} function quick(text:string){value.value=text;void send()} async function create(){await chat.crearConversacion()}
</script>
<template><div class="chat-page"><ChatSidebar @nueva="create"/><section class="chat-main"><header><div><h1>Orientación IA</h1><p>GPT-5.6 + reglas de seguridad + n8n</p></div><span class="online">● Activo</span></header><div v-if="chat.error" class="error">{{chat.error}}</div><ChatMessages ref="messagesRef" :escribiendo="chat.escribiendo"/><ChatInput v-model="value" :disabled="chat.escribiendo" @send="send" @quick="quick"/></section><section class="context"><div class="tabs"><button :class="{active:tab==='case'}" @click="tab='case'">Caso</button><button :class="{active:tab==='guide'}" @click="tab='guide'">Guía</button></div><HealthCasePanel v-if="tab==='case'" :health-case="cases.activeCase"/><GuidancePanel v-else :source-count="chat.ultimaRespuesta?.sources?.length"/></section></div></template>
<style scoped>.chat-page{height:calc(100vh);display:flex;background:#fff}.chat-main{flex:1;display:flex;flex-direction:column;min-width:0}.chat-main>header{height:72px;display:flex;justify-content:space-between;align-items:center;padding:0 1.2rem;border-bottom:1px solid var(--color-gray-200)}header h1{font-size:1.05rem;color:var(--color-navy)}header p{font-size:.72rem;color:var(--color-gray-500)}.online{font-size:.72rem;color:#15803d;background:#dcfce7;padding:.3rem .55rem;border-radius:999px}.error{margin:.65rem 1rem 0;background:#fff7ed;color:#9a3412;padding:.65rem;border-radius:8px;font-size:.8rem}.context{width:300px;border-left:1px solid var(--color-gray-200);display:flex;flex-direction:column}.tabs{display:grid;grid-template-columns:1fr 1fr;padding:.5rem;gap:.4rem;border-bottom:1px solid var(--color-gray-200)}.tabs button{padding:.45rem;border-radius:7px;background:#f1f5f9}.tabs button.active{background:#0e7490;color:#fff}@media(max-width:1100px){.context{display:none}}@media(max-width:850px){.chat-page{height:calc(100vh - 58px)}:deep(.chat-sidebar){display:none}}</style>
